  { name: "IKEA", homepage: "https://www.ikea.com/nl/nl/", blog: "https://www.ikea.com/nl/nl/ideas/", instagram: "https://www.instagram.com/ikea/", enabled: true },
  { name: "OTTO", homepage: "https://www.otto.de", blog: "https://www.otto.de/biorhythm/", instagram: "https://www.instagram.com/otto/", enabled: false },
  { name: "Home24", homepage: "https://www.home24.de", blog: "https://www.home24.de/wohnberatung/", instagram: "https://www.instagram.com/home24/", enabled: false },
  { name: "OBI", homepage: "https://www.obi.de", blog: "https://www.obi.de/ratgeber/", instagram: "https://www.instagram.com/obi_de/", enabled: false },
  { name: "JYSK", homepage: "https://jysk.nl", blog: "https://jysk.nl/inspiratie", instagram: "https://www.instagram.com/jysk/", enabled: false },
  { name: "Fonq", homepage: "https://www.fonq.nl", blog: "https://www.fonq.nl/inspiratie/", instagram: "https://www.instagram.com/fonq/", enabled: false },
