  { name: "Kees Smit Tuinmeubelen", homepage: "https://www.keessmit.nl", blog: "https://www.keessmit.nl/inspiratie", instagram: "https://www.instagram.com/keessmit/", enabled: false },
  { name: "ManoMano", homepage: "https://www.manomano.fr", blog: "https://www.manomano.fr/blog/", instagram: "https://www.instagram.com/manomano_fr/", enabled: false }
];

const analysisContext = "vidaXL's PR1 Navigate & Search program covers five milestones: (1) Content Quality, (2) PDP Navigation, (3) Search Improvement, (4) PLP Improvements, and (5) AI-powered Guided Shopping Assistant. The program follows a hypothesis-driven MVP approach with gate decisions rather than strict sequential delivery.";

const analyzerSystemPrompt = "You are a senior e-commerce CRO and UX analyst performing a competitor analysis benchmarking. Respond with ONLY valid JSON, matching exactly this schema: {\"ux_assessment\": string, \"blog_assessment\": string, \"social_assessment\": string, \"key_gaps_vs_target\": [string], \"recommendations\": [{\"milestone\": string, \"recommendation\": string, \"effort\": \"low|medium|high\"}]}";

const reportSystemPrompt = "You are preparing an executive competitor analysis report. Output clean, email-ready semantic HTML only. Wrap the Executive Summary section inside a beautifully styled border box card: <div style=\"background-color: #f8f9fa; border-left: 4px solid #ff6600; padding: 20px; border-radius: 6px; margin-bottom: 25px; font-family: Arial, sans-serif;\"><h3 style=\"margin-top: 0; color: #111; font-size: 18px;\">Executive Summary</h3><p style=\"line-height: 1.6; color: #333; margin: 0; font-size: 14px;\">[summary text]</p></div>. You MUST include a dedicated section titled '<h2>Prioritized Action Plan for the Target Company</h2>' outlining specific gaps, website design improvements, and concrete actions for the target company (e.g. vidaXL) to close gaps vs competitors, grouped by the Navigate & Search program milestones. Style headers cleanly, use inline CSS colors matching target company brand, and do not use markdown, no html/head/body wrapper tags, no comments outside the HTML.";

return [{ json: {
  targetCompany,
  competitors,
  analysisContext,
  analyzerSystemPrompt,
  reportSystemPrompt,
  groqApiKey: "",
  pagespeedApiKey: ""
} }];

const cfg = $input.first().json;

async function fetchText(url) {
  try {
    const res = await this.helpers.httpRequest({ method: 'GET', url, timeout: 10000, headers: { 'User-Agent': 'Mozilla/5.0 (compatible; CompetitorBot/1.0)' } });
    if (res instanceof Buffer) {
      return res.toString('utf8');
    }
    if (typeof res === 'object') {
      return JSON.stringify(res);
    }
    return String(res || '');
  } catch (e) {
    return '';
  }
}

function extractSignals(html) {
  if (typeof html !== 'string') {
    html = String(html || '');
  }
  const titleMatch = html.match(/<title>(.*?)<\/title>/i);
  const metaDescMatch = html.match(/<meta[^>]*name=[\"']description[\"'][^>]*content=[\"']([^\"']*)[\"']/i);
  const wordCount = html.replace(/<[^>]*>/g, ' ').split(/\s+/).filter(Boolean).length;
  const h1Count = (html.match(/<h1[\s>]/gi) || []).length;
  const h2Count = (html.match(/<h2[\s>]/gi) || []).length;
  const imgCount = (html.match(/<img[\s>]/gi) || []).length;

  const hasInstagram = /instagram\.com\/[a-zA-Z0-9_\.]+/i.test(html);
  const hasFacebook = /facebook\.com\/[a-zA-Z0-9_\.]+/i.test(html);
  const hasLinkedIn = /linkedin\.com\/company\/[a-zA-Z0-9_\.\-]+/i.test(html);
  const hasPinterest = /pinterest\.com\/[a-zA-Z0-9_\.]+/i.test(html);
  const hasYouTube = /youtube\.com\/(c\/|user\/|channel\/)?[a-zA-Z0-9_\.\-]+/i.test(html);
  const hasTwitter = /(twitter\.com|x\.com)\/[a-zA-Z0-9_\.]+/i.test(html);

  return {
    title: titleMatch ? titleMatch[1].trim() : null,
    metaDescription: metaDescMatch ? metaDescMatch[1].trim() : null,
    approxWordCount: wordCount,
    h1Count, h2Count, imgCount,
    socialLinks: {
      instagram: hasInstagram,
      facebook: hasFacebook,
      linkedin: hasLinkedIn,
      pinterest: hasPinterest,
      youtube: hasYouTube,
      twitter: hasTwitter
    }
  };
}

async function getPageSpeed(url, apiKey) {
  try {
    const endpoint = `https://www.googleapis.com/pagespeedonline/v5/runPagespeed?url=${encodeURIComponent(url)}&category=PERFORMANCE&category=SEO&category=ACCESSIBILITY&category=BEST_PRACTICES${apiKey ? '&key=' + apiKey : ''}`;
    const res = await this.helpers.httpRequest({ method: 'GET', url: endpoint, json: true, timeout: 25000 });
    const cats = (res && res.lighthouseResult && res.lighthouseResult.categories) || {};
    return {
      performance: cats.performance ? Math.round(cats.performance.score * 100) : null,
      seo: cats.seo ? Math.round(cats.seo.score * 100) : null,
      accessibility: cats.accessibility ? Math.round(cats.accessibility.score * 100) : null,
      bestPractices: cats['best-practices'] ? Math.round(cats['best-practices'].score * 100) : null
    };
  } catch (e) {
    return { performance: null, seo: null, accessibility: null, bestPractices: null, error: String(e.message || e) };
  }
}

const homepageHtml = await fetchText.call(this, cfg.targetCompany.homepage);
const blogHtml = await fetchText.call(this, cfg.targetCompany.blog);

const targetSignals = {
  homepage: extractSignals(homepageHtml),
  blog: extractSignals(blogHtml),
  pagespeed: await getPageSpeed.call(this, cfg.targetCompany.homepage, cfg.pagespeedApiKey)
};

return [{ json: {
  targetSignals,
  competitors: cfg.competitors,
  analysisContext: cfg.analysisContext,
  pagespeedApiKey: cfg.pagespeedApiKey
} }];

