const data = $input.first().json;
const html = (data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content) || '<p>No report generated.</p>';
const today = new Date().toISOString().slice(0,10);
const targetName = $('Define Config').item.json.targetCompany.name;

const analyses = $('Aggregate Competitor Analyses').first().json.competitorAnalyses || [];

if (analyses.length === 0) {
  return [{ json: {
    subject: `No Competitors Selected – ${targetName} Report`,
    htmlBody: `<h1>${targetName} Competitor Analysis Report</h1><p style="color:#666">Generated ${today}</p><div style="background-color: #fff3cd; border-left: 4px solid #856404; padding: 20px; border-radius: 6px; color: #856404; font-family: Arial, sans-serif; margin-top: 25px;"><h3>No Competitors Selected</h3><p style="margin: 0; line-height: 1.5;">You did not select any competitors for this benchmarking run. Please open the dashboard at <a href="http://localhost:3000">http://localhost:3000</a>, check/select at least one competitor, and trigger the analysis scraper again.</p></div>`
  } }];
}

const competitorDetailsHtml = analyses.map(c => {
  const a = c.analysis || {};
  const gapsList = (a.key_gaps_vs_target || []).map(g => `<li>${g}</li>\n`).join('');
  const recsList = (a.recommendations || []).map(r => `
    <tr>
      <td style="padding: 6px; border: 1px solid #eee;"><strong>${r.milestone}</strong></td>
      <td style="padding: 6px; border: 1px solid #eee;">${r.recommendation}</td>
      <td style="padding: 6px; border: 1px solid #eee; text-align: center;">
        <span style="padding: 2px 6px; border-radius: 4px; font-size: 11px; background: ${r.effort === 'low' ? '#e2f9e1; color: #1e7e1c;' : r.effort === 'medium' ? '#fff3cd; color: #856404;' : '#f8d7da; color: #721c24;'}">${r.effort}</span>
      </td>
    </tr>
  `).join('');

  return `
    <div style="margin-top: 30px; padding: 20px; border: 1px solid #e0e0e0; border-radius: 8px; background-color: #fafafa; font-family: Arial, sans-serif;">
      <h3 style="margin-top: 0; color: #ff6600; border-bottom: 2px solid #ff6600; padding-bottom: 6px; font-size: 18px;">${c.competitorName} Detailed Analysis</h3>

      <p style="font-size: 14px; line-height: 1.5; color: #333;"><strong>UX & Performance Assessment:</strong><br/>${a.ux_assessment || 'N/A'}</p>
      <p style="font-size: 14px; line-height: 1.5; color: #333;"><strong>Blog Content & Cadence Assessment:</strong><br/>${a.blog_assessment || 'N/A'}</p>
      <p style="font-size: 14px; line-height: 1.5; color: #333;"><strong>Social Media Presence Assessment:</strong><br/>${a.social_assessment || 'N/A'}</p>

      <h4 style="margin-bottom: 8px; color: #333; font-size: 15px;">Key Gaps vs. ${targetName}:</h4>
      <ul style="margin-top: 0; padding-left: 20px; font-size: 14px; line-height: 1.5; color: #333;">
        ${gapsList || '<li>No significant gaps identified.</li>'}
      </ul>

      <h4 style="margin-bottom: 8px; color: #333; font-size: 15px;">Actionable Recommendations:</h4>
      <table style="width: 100%; border-collapse: collapse; margin-top: 8px; font-size: 13px;">
        <thead>
          <tr style="background: #eee;">
            <th style="padding: 6px; border: 1px solid #ddd; text-align: left;">Milestone</th>
            <th style="padding: 6px; border: 1px solid #ddd; text-align: left;">Recommendation</th>
            <th style="padding: 6px; border: 1px solid #ddd; text-align: center; width: 80px;">Effort</th>
          </tr>
        </thead>
        <tbody>
          ${recsList || '<tr><td colspan="3" style="padding: 10px; text-align: center; color: #999;">No recommendations.</td></tr>'}
        </tbody>
      </table>
    </div>
  `;
}).join('');

const analyzedNames = analyses.map(c => c.competitorName).join(', ');

return [{ json: {
  subject: `${targetName} Competitor Analysis Report – ${today}`,
  htmlBody: `<h1>${targetName} Competitor Analysis Report</h1><p style="color:#666">Generated ${today} &middot; Benchmarked against analyzed competitors: <strong>${analyzedNames}</strong></p>${html}<hr style="margin-top: 40px; border: 0; border-top: 1px dashed #ccc;"/><h2 style="color: #ff6600;">Competitor Deep Dives</h2>${competitorDetailsHtml}`
} }];

const item = $input.first().json;
const htmlContent = item.htmlBody || '';
return [{
  json: {
    fileName: 'competitor_analysis_report.html'
  },
  binary: {
    data: {
      data: Buffer.from(htmlContent).toString('base64'),
      mimeType: 'text/html',
      fileName: 'competitor_analysis_report.html'
    }
  }
}];
